module RefModule(
   // Outputs
   output reg out,
   // Inputs
   input clk,
   input in,
   input reset
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
      if (reset) begin
         out <= 1'b0;
      end else if (in) begin
         out <= ~out;
      end
   end

endmodule
